173	async function readLocalPacksChanged(gh, fullName, commits) {
174	  for (const c of commits) {
175	    if (!c?.sha) continue;
176	    const detail = await gh(`/repos/${fullName}/commits/${c.sha}`);
177	    const files = detail.status === 200 ? (detail.json?.files ?? []) : [];
178	    if (files.some((f) => typeof f.filename === 'string' && f.filename.startsWith('.claudinite/local_packs/'))) return true;
