186	// global object ({ changed, packs, crossCutting }), computed once by the caller and
187	// threaded in; the per-repo `relevantCanonChanged` is derived from it against this
188	// member's declared packs.
189	//
190	// Two signals exist only on the HOME repo's bundle and are stamped by the planner,
191	// not built here: `isHome: true`, and `fleetMembers` — every successfully-probed
192	// member's { repo, activePacks, packConfigs, projectChanged, substantiveChange,
193	// hasLocalPacks, localPacksChanged }, complete because home is planned last.
194	// They're what home-only packs' gates decide fleet-facing work from.
195	export async function buildSignals(gh, repo, { sinceIso, weekdayUtc, canonChange }) {
196	  const fullName = repo.full_name;
197	  const defaultBranch = repo.default_branch;
198	  const fullSweep = isFullSweepDay(fullName, weekdayUtc);
199	  const pushedInWindow = repo.pushed_at ? new Date(repo.pushed_at) >= new Date(sinceIso) : false;
200	
201	  let mainMoved = false;
202	  let substantiveChange = false;
203	  let commits = [];
204	  if (pushedInWindow || fullSweep) {
205	    const { status, json } = await gh(
206	      `/repos/${fullName}/commits?sha=${encodeURIComponent(defaultBranch)}&since=${sinceIso}&per_page=100`,
207	    );
208	    commits = status === 200 && Array.isArray(json) ? json : [];
209	    mainMoved = commits.length > 0;
210	    // Real project work in the window (not fleet/CI housekeeping) — the trigger the
211	    // growth tasks AND repo-tidy key on, so a bot bump or a nightly baselining commit
212	    // doesn't spawn a subagent that finds nothing. (A housekeeping commit that also
213	    // merged a PR would land the PR — but a PR merge is itself a substantive commit, so
214	    // it already trips substantiveChange; the pure-baselining case has no such merge.)
215	    substantiveChange = commits.some(isSubstantiveCommit);
216	  }
217	  // The default branch advancing (merges land there too) is "the project changed".
218	  const projectChanged = mainMoved;
219	  // Widen the tidy candidate set (re-examine ALL open branches/PRs/issues for landed /
220	  // implemented status) only on a *substantive* move or the weekly full sweep — not on
221	  // a housekeeping-only main move, which lands nothing and implements nothing.
222	  const widen = substantiveChange || fullSweep;
223	
224	  const prsTouched = await touchedNumbers(gh, `/repos/${fullName}/pulls?state=open&sort=updated&direction=desc`, sinceIso, widen);
225	  const issuesTouched = await touchedNumbers(gh, `/repos/${fullName}/issues?state=open&sort=updated&direction=desc`, sinceIso, widen, (i) => !i.pull_request && !isRoutineTracker(i.title));
226	  const branchesTouched = widen ? await allBranchNames(gh, fullName) : [];
227	  const { activePacks, packConfigs } = await readPacksDeclaration(gh, fullName);
228	  const hasLocalPacks = await readHasLocalPacks(gh, fullName);
229	  // Only meaningful (and only worth the per-commit reads) when the repo has local packs.
230	  const localPacksChanged = hasLocalPacks && commits.length ? await readLocalPacksChanged(gh, fullName, commits) : false;
231	
232	  const canon = canonChange ?? { changed: false, packs: new Set(), crossCutting: false };
233	  // This member cares about a canon change iff a pack it declares moved, or a
234	  // cross-cutting area (mounted by everyone) moved.
235	  const relevantCanonChanged = canon.crossCutting || activePacks.some((p) => canon.packs.has(p));
236	
237	  return {
238	    fullSweep,
239	    pushedAt: repo.pushed_at ?? null,
240	    mainMoved,
241	    projectChanged,
242	    substantiveChange,
243	    prsTouched,
244	    issuesTouched,
245	    branchesTouched,
246	    activePacks,
247	    packConfigs,
248	    hasLocalPacks,
249	    localPacksChanged,
250	    canonChanged: !!canon.changed,
251	    relevantCanonChanged,
252	  };
253	}
254

